head.b:skin:
  :root {
    --background: #ffffff;
    --foreground: #0f172a;
    --primary: #f97316;
    --primary-foreground: #ffffff;
    --secondary: #f1f5f9;
    --accent: #10b981;
    --muted-foreground: #64748b;
    --border: #e2e8f0;
    --shadow: 0 20px 40px rgba(15, 23, 42, .08);
  }

  * {
    box-sizing: border-box;
    margin: 0;
    padding: 0;
  }

  html {
    scroll-behavior: smooth;
  }

  body {
    font-family: "Inter", sans-serif;
    color: var(--foreground);
    background: var(--background);
    line-height: 1.6;
  }

  a {
    color: inherit;
    text-decoration: none;
  }

  img,
  svg {
    display: block;
    max-width: 100%;
  }

  .mono {
    font-family: "JetBrains Mono", monospace;
  }

  .container {
    width: min(1280px, calc(100% - 48px));
    margin: 0 auto;
  }

  .site-nav {
    position: sticky;
    top: 0;
    z-index: 50;
    background: rgba(255, 255, 255, .82);
    backdrop-filter: blur(16px);
    -webkit-backdrop-filter: blur(16px);
    border-bottom: 1px solid var(--border);
  }

  .site-nav .nav-inner {
    min-height: 76px;
    display: flex;
    align-items: center;
    justify-content: space-between;
    gap: 24px;
  }

  .brand {
    display: flex;
    align-items: center;
    gap: 10px;
  }

  .brand-box {
    width: 32px;
    height: 32px;
    background: var(--primary);
    border-radius: 4px;
    position: relative;
  }

  .brand-box::before {
    content: 'L';
    position: absolute;
    left: 9px;
    top: 2px;
    color: #0f172a;
    font-size: 1.65rem;
    font-weight: 900;
    font-style: italic;
  }

  .brand-name {
    font-size: 1.25rem;
    font-weight: 900;
    letter-spacing: -.05em;
  }

  .nav-links {
    display: flex;
    gap: 32px;
    font-size: .875rem;
    font-weight: 600;
    text-transform: uppercase;
    letter-spacing: .08em;
  }

  .nav-links a:hover {
    color: var(--primary);
  }

  .btn-primary,
  .btn-secondary {
    display: inline-flex;
    align-items: center;
    justify-content: center;
    border-radius: 999px;
    min-height: 48px;
    padding: 0 24px;
    font-weight: 800;
    transition: transform .2s ease, box-shadow .2s ease;
  }

  .btn-primary:hover,
  .btn-secondary:hover {
    transform: translateY(-1px);
    box-shadow: 0 16px 28px rgba(0, 0, 0, .1);
  }

  .btn-primary {
    background: var(--primary);
    color: var(--primary-foreground);
  }

  .btn-secondary {
    border: 1px solid var(--border);
    background: #ffffff;
    color: var(--foreground);
  }

  .hero {
    padding: 80px 0 120px;
    border-bottom: 1px solid var(--border);
  }

  .hero-grid {
    display: grid;
    grid-template-columns: repeat(12, minmax(0, 1fr));
    gap: 32px;
  }

  .hero-main {
    grid-column: span 8;
  }

  .hero-aside {
    grid-column: span 4;
    align-self: end;
  }

  .tagline {
    display: inline-flex;
    align-items: center;
    gap: 10px;
    margin-bottom: 24px;
    color: var(--primary);
    font-size: .875rem;
  }

  .tagline span {
    font-size: 1rem;
  }

  h1 {
    font-size: clamp(4rem, 9vw, 9rem);
    line-height: .85;
    letter-spacing: -.06em;
    font-weight: 900;
    text-transform: uppercase;
  }

  h1 .text-primary {
    color: var(--primary);
  }

  .hero-details {
    display: flex;
    flex-wrap: wrap;
    gap: 48px;
    margin-top: 48px;
  }

  .hero-label {
    font-size: .75rem;
    color: var(--muted-foreground);
    text-transform: uppercase;
    margin-bottom: 4px;
  }

  .hero-value {
    font-size: 1.25rem;
    font-weight: 800;
  }

  .hero-aside .divider {
    height: 1px;
    background: var(--border);
    margin-bottom: 32px;
  }

  .hero-aside p {
    color: var(--muted-foreground);
    font-size: 1.125rem;
  }

  .hero-illustration {
    grid-column: span 4;
    align-self: center;
  }

  .hero-illustration svg {
    width: 100%;
    border-radius: 24px;
    box-shadow: var(--shadow);
  }

  .hero-note {
    margin: 18px 12px 0;
    color: var(--muted-foreground);
    font-size: .875rem;
  }

  .hero-note strong {
    display: block;
    margin-bottom: 4px;
    color: var(--foreground);
  }

  .section {
    padding: 96px 0;
  }

  .section.secondary {
    background: var(--secondary);
  }

  .eyebrow {
    margin-bottom: 12px;
    color: var(--primary);
    font-size: .75rem;
    text-transform: uppercase;
    letter-spacing: .14em;
  }

  .section-title {
    font-size: clamp(2rem, 4vw, 4rem);
    line-height: 1;
    letter-spacing: -.04em;
    margin-bottom: 24px;
    font-weight: 800;
  }

  .section-title.upper {
    text-transform: uppercase;
  }

  .section-description {
    color: var(--muted-foreground);
    max-width: 680px;
  }

  .about-grid,
  .calls-grid,
  .footer-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 32px;
  }

  .about-image {
    width: 100%;
    aspect-ratio: 16 / 9;
    object-fit: cover;
    border-radius: 6px;
    box-shadow: 0 0 0 1px rgba(0,0,0,.05);
  }

  .stats-grid {
    display: grid;
    grid-template-columns: repeat(2, minmax(0, 1fr));
    gap: 16px;
    margin-top: 24px;
  }

  .stat-card {
    padding: 16px;
    background: #ffffff;
    border-left: 4px solid var(--primary);
  }

  .stat-card.accent {
    border-left-color: var(--accent);
  }

  .stat-value {
    display: block;
    font-size: 2rem;
    font-weight: 800;
  }

  .stat-label {
    color: var(--muted-foreground);
    font-size: .75rem;
    text-transform: uppercase;
  }

  .timeline {
    max-width: 860px;
    margin: 0 auto;
    display: grid;
    gap: 16px;
  }

  .timeline-item {
    display: flex;
    gap: 32px;
  }

  .timeline-date {
    width: 56px;
    flex: 0 0 56px;
    color: var(--primary);
    font-weight: 800;
    padding-top: 4px;
  }

  .timeline-content {
    position: relative;
    padding: 0 0 48px 32px;
    border-left: 1px solid var(--border);
  }

  .timeline-content.last {
    padding-bottom: 0;
  }

  .timeline-marker {
    position: absolute;
    left: -5px;
    top: 8px;
    width: 9px;
    height: 9px;
    border-radius: 50%;
    background: var(--primary);
  }

  .timeline-title {
    margin-bottom: 8px;
    font-size: 1.25rem;
    font-weight: 800;
    text-transform: uppercase;
  }

  .timeline-description {
    color: var(--muted-foreground);
  }

  .calls-head {
    margin-bottom: 64px;
  }

  .call-card {
    min-height: 360px;
    border-radius: 24px;
    padding: 40px;
    display: flex;
    flex-direction: column;
    justify-content: space-between;
  }

  .call-card.dark {
    background: var(--foreground);
    color: #ffffff;
  }

  .call-card.light {
    background: var(--secondary);
    border: 1px solid var(--border);
  }

  .call-card-description {
    color: rgba(255,255,255,.68);
  }

  .call-card.light .call-card-description {
    color: var(--muted-foreground);
  }

  .icon-wrap {
    width: 56px;
    height: 56px;
    border-radius: 18px;
    display: flex;
    align-items: center;
    justify-content: center;
    margin-bottom: 32px;
  }

  .call-title {
    margin-bottom: 16px;
    font-size: 2rem;
    font-weight: 800;
  }

  .contact-list {
    display: grid;
    gap: 12px;
    margin-top: 24px;
  }

  .contact-link {
    display: flex;
    align-items: center;
    min-height: 60px;
    padding: 0 24px;
    border-radius: 16px;
    border: 1px solid var(--border);
    background: #ffffff;
    font-weight: 600;
  }

  .sponsors-header {
    display: flex;
    justify-content: space-between;
    align-items: end;
    gap: 24px;
    margin-bottom: 48px;
  }

  .sponsors-link {
    color: var(--primary);
    font-size: .875rem;
    font-weight: 800;
    text-transform: uppercase;
    letter-spacing: .08em;
    border-bottom: 2px solid var(--primary);
    padding-bottom: 4px;
  }

  .sponsors-grid {
    display: grid;
    grid-template-columns: repeat(5, minmax(0, 1fr));
    gap: 24px;
  }

  .sponsor-logo {
    height: 64px;
    border-radius: 8px;
    background: #ffffff;
    border: 1px solid var(--border);
    display: flex;
    align-items: center;
    justify-content: center;
    color: var(--muted-foreground);
    font-size: .75rem;
    text-transform: uppercase;
    letter-spacing: .14em;
  }

  .site-footer {
    background: var(--foreground);
    color: #ffffff;
    padding: 96px 0 48px;
  }

  .footer-eyebrow {
    color: var(--primary);
    margin-bottom: 16px;
    font-size: .75rem;
    text-transform: uppercase;
    letter-spacing: .14em;
  }

  .footer-title {
    font-size: clamp(3rem, 6vw, 4.5rem);
    font-weight: 900;
    line-height: 1;
    text-transform: uppercase;
    margin-bottom: 32px;
  }

  .footer-description {
    max-width: 28rem;
    color: rgba(255,255,255,.6);
  }

  .signup-form {
    display: grid;
    gap: 24px;
  }

  .form-label {
    display: block;
    margin-bottom: 8px;
    color: rgba(255,255,255,.4);
    font-size: .75rem;
    text-transform: uppercase;
  }

  .form-input,
  .form-select {
    width: 100%;
    background: transparent;
    color: #ffffff;
    border: 0;
    border-bottom: 1px solid rgba(255,255,255,.2);
    padding: 12px 0;
    outline: 0;
  }

  .form-select option {
    color: var(--foreground);
  }

  .btn-submit {
    width: 100%;
    border: 0;
    background: var(--primary);
    color: #ffffff;
    padding: 20px;
    font-size: 1.25rem;
    font-weight: 900;
    text-transform: uppercase;
    cursor: pointer;
  }

  .footer-bottom {
    display: flex;
    justify-content: space-between;
    gap: 24px;
    padding-top: 48px;
    margin-top: 48px;
    border-top: 1px solid rgba(255,255,255,.1);
    color: rgba(255,255,255,.4);
    font-size: .75rem;
    text-transform: uppercase;
    letter-spacing: .14em;
  }

  .blogger-content-section {
    display: none;
  }

  /* Blogger renders the required empty section with the .section class. */
  #main {
    display: none !important;
  }

  @media (max-width: 980px) {
    .nav-links,
    .hero-main,
.hero-aside,
.hero-illustration,
    .about-grid,
    .calls-grid,
    .footer-grid,
    .sponsors-grid {
      grid-template-columns: 1fr;
    }

    .hero-main,
    .hero-aside,
    .hero-illustration {
      grid-column: span 12;
    }

    .sponsors-grid {
      display: grid;
    }

    .sponsors-header,
    .footer-bottom {
      flex-direction: column;
      align-items: start;
    }
  }

  @media (max-width: 720px) {
    .container {
      width: min(1280px, calc(100% - 24px));
    }

    .site-nav .nav-inner {
      min-height: 70px;
      flex-wrap: wrap;
      padding: 12px 0;
    }

    .site-nav .nav-inner .btn-primary {
      width: 100%;
    }

    .hero {
      padding: 48px 0 72px;
    }

    .hero-details {
      gap: 24px;
    }

    .timeline-item {
      gap: 20px;
    }

    .call-card,
    .site-footer {
      padding-left: 0;
      padding-right: 0;
    }
  }
